#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Carp;

# Database configuration - should be moved to environment variables or config file
# WARNING: Hardcoded credentials are a security risk. Use environment variables instead.
my $db_name = $ENV{'LEGACY_DB_NAME'} || 'legacy_db';
my $db_host = $ENV{'LEGACY_DB_HOST'} || 'localhost';
my $db_user = $ENV{'LEGACY_DB_USER'} || die "Error: LEGACY_DB_USER environment variable not set. Refusing to use hardcoded credentials.\n";
my $db_pass = $ENV{'LEGACY_DB_PASS'} || die "Error: LEGACY_DB_PASS environment variable not set. Refusing to use hardcoded credentials.\n";
my $db_port = $ENV{'LEGACY_DB_PORT'} || 3306;

my $dsn = "DBI:mysql:database=$db_name;host=$db_host;port=$db_port";

sub get_db_connection {
    my $dbh = DBI->connect(
        $dsn,
        $db_user,
        $db_pass,
        {
            RaiseError       => 1,
            AutoCommit       => 1,
            PrintError       => 0,
            mysql_enable_utf8 => 1,
            mysql_auto_reconnect => 1,
        }
    ) or croak "Failed to connect to database: " . DBI->errstr;

    return $dbh;
}

sub disconnect_db {
    my ($dbh) = @_;
    if ($dbh && $dbh->ping) {
        $dbh->disconnect();
    }
    return;
}

sub execute_query {
    my ($dbh, $sql, @bind_params) = @_;

    my $sth = $dbh->prepare($sql)
        or croak "Failed to prepare statement: " . $dbh->errstr;

    $sth->execute(@bind_params)
        or croak "Failed to execute statement: " . $sth->errstr;

    return $sth;
}

sub fetch_all_rows {
    my ($dbh, $sql, @bind_params) = @_;

    my $sth = execute_query($dbh, $sql, @bind_params);
    my $results = $sth->fetchall_arrayref({});
    $sth->finish();

    return $results;
}

sub fetch_single_row {
    my ($dbh, $sql, @bind_params) = @_;

    my $sth = execute_query($dbh, $sql, @bind_params);
    my $row = $sth->fetchrow_hashref();
    $sth->finish();

    return $row;
}

sub test_connection {
    my $dbh = get_db_connection();

    if ($dbh->ping) {
        print "Database connection successful.\n";

        my $row = fetch_single_row($dbh, "SELECT NOW() AS current_time, VERSION() AS db_version");
        if ($row) {
            print "Server Time: $row->{current_time}\n";
            print "MySQL Version: $row->{db_version}\n";
        }

        my $tables = fetch_all_rows($dbh, "SHOW TABLES");
        if ($tables && @$tables) {
            print "Number of tables in $db_name: " . scalar(@$tables) . "\n";
        }
    } else {
        print "Database connection failed.\n";
    }

    disconnect_db($dbh);
    return;
}

# Run connection test if executed directly
